module RefModule (
    input wire clk,
    input wire rst,
    input wire signal_in,
    output reg edge_out
);
    reg unused_signal_in_d;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            edge_out <= 0;
            unused_signal_in_d <= 0;
        end else begin
            edge_out <= (signal_in && !unused_signal_in_d);
            unused_signal_in_d <= signal_in;
        end
    end
endmodule
